transform.script:
const taskText = triggeringMessage.content?.text || '';
if (!taskText || !taskText.trim()) throw new Error('ISSUE_OPENED has no text content — nothing to draft');

return {
  topic: 'CLUSTER_OPERATIONS',
  content: {
    text: '[DOC:PRISM] routed',
    data: {
      operations: [
        {
          action: 'load_config',
          config: {
            base: 'doc-draft-workflow',
            params: {
              tier: 'prism',
              drafter_level: 'level3',
              validator_count: 3,
              max_iterations: 5,
              max_tokens: 150000,
              has_action_items: false
            }
          }
        },
        {
          action: 'publish',
          topic: 'ISSUE_OPENED',
          content: { text: taskText },
          metadata: { _republished: true }
        }
      ]
    }
  }
};
